def generate():
    binary = binascii.unhexlify("".join(HEX_DATA))
    count = len(binary) // 50
    # Create valid Binary STL header
    header = b"BUILD123D_REAR_PLATE_RECONSTRUCTION".ljust(80, b"\x00")
    payload = header + struct.pack("<I", count) + binary
    
    with open("temp_rear.stl", "wb") as f_out: f_out.write(payload)
    part = import_stl("temp_rear.stl")
    os.remove("temp_rear.stl")
    
    # Save output STL in results folder
    output_dir = os.path.dirname(os.path.dirname(__file__))
    output_path = os.path.join(output_dir, "Rear_Final_Build123d.stl")
    export_stl(part, output_path)
    print("--- SUCCESS ---")
    print(f"Generated: {output_path}")

if __name__ == "__main__":
    generate()
